190	fn rbtdrk_git_add_and_commit_paths(
191	    root: &Path,
192	    files: &[&str],
193	    message: &str,
194	) -> Result<(), String> {
195	    let mut add_args: Vec<&str> = vec!["add"];
196	    add_args.extend_from_slice(files);
197	    let add = Command::new("git")
198	        .args(&add_args)
199	        .current_dir(root)
200	        .output()
201	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
202	    if !add.status.success() {
203	        return Err(format!(
204	            "rbtdrk: git add failed (exit {}): {}",
205	            add.status.code().unwrap_or(-1),
206	            String::from_utf8_lossy(&add.stderr).trim()
207	        ));
208	    }
209	    let commit = Command::new("git")
210	        .args(["commit", "-m", message])
211	        .current_dir(root)
212	        .output()
213	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
214	    if !commit.status.success() {
215	        return Err(format!(
216	            "rbtdrk: git commit failed (exit {}): {}",
217	            commit.status.code().unwrap_or(-1),
218	            String::from_utf8_lossy(&commit.stderr).trim()
219	        ));
220	    }
221	    Ok(())
222	}
