224	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
225	pub(crate) fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
226	    let rbrr = root.join(RBTDGC_RBRR_FILE);
227	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
228	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
229	    if secrets_dir.is_empty() {
230	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
231	    }
232	    Ok(rbtdrk_resolve(root, &secrets_dir)
233	        .join(role)
234	        .join(RBTDGC_RBRA_FILE))
235	}
