237	// ── Canonical-prefix install (case 1) ───────────────────────
238	
239	/// Idempotently install canc-/canr- prefixes. CLOUD_PREFIX lands in rbrd.env,
240	/// RUNTIME_PREFIX lands in rbrr.env. Returns Ok without committing when both
241	/// already match the canonical markers; otherwise rewrites both files and
242	/// commits in one go.
243	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
244	    let rbrr = root.join(RBTDGC_RBRR_FILE);
245	    let rbrd = root.join(RBTDGC_RBRD_FILE);
246	    let tincture = rbtdrk_burs_tincture()?;
247	    let cloud_target = rbtdrk_canonical_cloud_prefix(&tincture);
248	    let runtime_target = rbtdrk_canonical_runtime_prefix(&tincture);
249	
250	    let cloud = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
251	    let runtime =
252	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
253	    if cloud == cloud_target && runtime == runtime_target {
254	        return Ok(());
255	    }
256	
257	    if cloud != cloud_target {
258	        let content = std::fs::read_to_string(&rbrd)
259	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
260	        let new_content = rbtdrk_replace_env_fields(
261	            &content,
262	            &[(RBTDRK_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
263	        );
264	        std::fs::write(&rbrd, &new_content)
265	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
266	    }
267	
268	    if runtime != runtime_target {
269	        let content = std::fs::read_to_string(&rbrr)
270	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
271	        let new_content = rbtdrk_replace_env_fields(
272	            &content,
273	            &[(RBTDRK_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
274	        );
275	        std::fs::write(&rbrr, &new_content)
276	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
277	    }
278	
279	    let commit_msg = format!(
280	        "canonical-establish fixture: install canonical prefixes ({}/{})",
281	        cloud_target, runtime_target
282	    );
283	    rbtdrk_git_add_and_commit_paths(
284	        root,
285	        &[RBTDGC_RBRR_FILE, RBTDGC_RBRD_FILE],
286	        &commit_msg,
287	    )
288	}
