305	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
306	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
307	    let rbrd = root.join(RBTDGC_RBRD_FILE);
308	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
