313	/// Cloud-prefix subdir name used in depot fact-file layout
314	/// (`<cloud_prefix>/<moniker>.depot`). Derived from RBRD_CLOUD_PREFIX with
315	/// the structural trailing `-` stripped so it matches the filesystem layout
316	/// emitted by zrbgp_depot_state_emit.
317	fn rbtdrk_cloud_prefix_subdir(root: &Path) -> Result<String, String> {
318	    let rbrd = root.join(RBTDGC_RBRD_FILE);
319	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
320	        .ok_or_else(|| format!("RBRD_CLOUD_PREFIX missing from {}", rbrd.display()))?;
321	    Ok(cloud_prefix.trim_end_matches('-').to_string())
322	}
