324	/// Pick the next free moniker for `family_stem` by walking the depot_list
325	/// invocation's BURV output dir for `<family>NNNNNN.depot` files under the
326	/// current cloud_prefix subdir. Returns
327	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
328	/// Restricting the walk to the current cloud_prefix is what makes allocation
329	/// collision-safe: a same-numbered moniker under a foreign cloud_prefix is
330	/// correctly ignored.
331	///
332	/// Caller contract: `list_result` MUST be from a freshly-invoked depot_list
333	/// that ran in the current process. The fact-file scan IS the collision
334	/// check — stale state means picking a colliding moniker. Do not reuse a
335	/// `list_result` across cases or pass an operator-cached value.
336	fn rbtdrk_pick_next_moniker(
337	    list_result: &rbtdri_InvokeResult,
338	    root: &Path,
339	    family_stem: &str,
340	) -> Result<String, String> {
341	    let prefix_dir = rbtdrk_cloud_prefix_subdir(root)?;
342	    let dir = list_result
343	        .burv_output
344	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
345	        .join(&prefix_dir);
346	    let entries = match std::fs::read_dir(&dir) {
347	        Ok(e) => e,
348	        Err(_) => {
349	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
350	        }
351	    };
352	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
353	    let mut max_suffix: Option<u32> = None;
354	    for entry in entries.flatten() {
355	        let name = match entry.file_name().into_string() {
356	            Ok(n) => n,
357	            Err(_) => continue,
358	        };
359	        let stem = match name.strip_suffix(&suffix_ext) {
360	            Some(s) => s,
361	            None => continue,
362	        };
363	        let numeric = match stem.strip_prefix(family_stem) {
364	            Some(s) => s,
365	            None => continue,
366	        };
367	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
368	            continue;
369	        }
370	        let parsed: u32 = match numeric.parse() {
371	            Ok(n) => n,
372	            Err(_) => continue,
373	        };
374	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
375	    }
376	    let next = match max_suffix {
377	        Some(m) => m + 1,
378	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
379	    };
380	    Ok(format!("{}{}", family_stem, next))
381	}
