383	fn rbtdrk_invoke_logged(
384	    ctx: &mut rbtdri_Context,
385	    colophon: &str,
386	    args: &[&str],
387	    extra_env: &[(&str, &str)],
388	    dir: &Path,
389	    label: &str,
390	) -> Result<rbtdri_InvokeResult, String> {
