399	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
400	/// have no context, so they read the project root from current_dir() — theurge
401	/// always launches from the project root.
402	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
403	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
