408	/// blank-template shape.
409	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
410	    let root = rbtdrk_probe_root()?;
411	    let rbrr = root.join(RBTDGC_RBRR_FILE);
412	    if !rbrr.exists() {
413	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
414	    }
415	    Ok(())
