418	/// Case 2 probe: canonical depot moniker installed in rbrd.env. Established
419	/// by case 1; absence means depot-levy didn't run or rbrd.env was rewritten.
420	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
421	    let root = rbtdrk_probe_root()?;
422	    let rbrd = root.join(RBTDGC_RBRD_FILE);
423	    let tincture = rbtdrk_burs_tincture()?;
424	    let family_stem = rbtdrk_family_stem(&tincture);
425	    let moniker =
426	        rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_DEPOT_MONIKER).unwrap_or_default();
427	    if !moniker.starts_with(&family_stem) {
428	        return Err(format!(
429	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
430	            RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker, family_stem
431	        ));
432	    }
433	    Ok(())
434	}
