449	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
450	/// fresh canest moniker, levies the depot, cross-checks project_id from
451	/// fact-file against the RBDC compose derivation.
452	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
453	    let probe = rbtdrb_Probe {
454	        name: "rbrr.env present",
455	        check: rbtdrk_probe_rbrr_present,
456	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
457	    };
458	    if let Err(v) = rbtdrb_assert(&probe) {
459	        return v;
460	    }
461	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
462	}
