464	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
465	    let root = ctx.project_root().to_path_buf();
466	
467	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
468	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
469	    }
470	
471	    let list_pre = match rbtdrk_invoke_logged(
472	        ctx,
473	        RBTDGC_LIST_DEPOT,
474	        &[],
475	        &[],
476	        dir,
477	        "list-pre",
478	    ) {
479	        Ok(r) => r,
