703	/// Shared invest body for retriever and director: invest → assert assay
704	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
705	fn rbtdrk_role_invest_impl(
706	    ctx: &mut rbtdri_Context,
707	    dir: &Path,
708	    divest_colophon: &str,
709	    invest_colophon: &str,
710	    identity: &str,
711	    role: &str,
712	) -> rbtdre_Verdict {
713	    let root = ctx.project_root().to_path_buf();
714	
715	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
716	        Ok(p) => p,
717	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
718	    };
719	
720	    // Invest is fail-loud if the SA already exists (RBSRK/RBSDK preflight), so a
721	    // standing-depot rerun must clear the prior SA first. The divest tabtarget is
722	    // 404-tolerant and confirms the SA is gone before returning, so on a
723	    // freshly-levied depot (canonical-establish) this is a clean no-op and on a
724	    // rerun (canonical-invest) it leaves the invest race-free.
725	    let label_divest = format!("divest-{}", role);
726	    let divest = match rbtdrk_invoke_logged(
727	        ctx,
728	        divest_colophon,
729	        &[identity],
730	        &[],
731	        dir,
732	        &label_divest,
733	    ) {
734	        Ok(r) => r,
735	        Err(e) => return rbtdre_Verdict::Fail(format!("divest {}: {}", role, e)),
736	    };
737	    if divest.exit_code != 0 {
738	        return rbtdre_Verdict::Fail(format!(
739	            "divest {} exit {}\n{}",
740	            role, divest.exit_code, divest.stderr
741	        ));
742	    }
743	
744	    let label_invest = format!("invest-{}", role);
745	    let invest = match rbtdrk_invoke_logged(
746	        ctx,
747	        invest_colophon,
748	        &[identity],
749	        &[],
750	        dir,
751	        &label_invest,
752	    ) {
753	        Ok(r) => r,
754	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
755	    };
756	    if invest.exit_code != 0 {
757	        return rbtdre_Verdict::Fail(format!(
758	            "invest {} exit {}\n{}",
759	            role, invest.exit_code, invest.stderr
760	        ));
761	    }
762	
763	    if !assay.exists() {
764	        return rbtdre_Verdict::Fail(format!(
765	            "assay RBRA absent after invest-{}: {}",
766	            role,
767	            assay.display()
768	        ));
769	    }
770	
771	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
772	        Ok(p) => p,
773	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
774	    };
775	    if let Some(parent) = canonical.parent() {
776	        if let Err(e) = std::fs::create_dir_all(parent) {
777	            return rbtdre_Verdict::Fail(format!(
778	                "create {} RBRA dir {}: {}",
779	                role,
780	                parent.display(),
781	                e
782	            ));
783	        }
784	    }
785	    if let Err(e) = std::fs::copy(&assay, &canonical) {
786	        return rbtdre_Verdict::Fail(format!(
787	            "copy assay RBRA → {} canonical {}: {}",
788	            role,
789	            canonical.display(),
790	            e
791	        ));
792	    }
793	
794	    let probe_colophon = match rbtdrm_credential_check_colophon(role) {
795	        Some(c) => c,
796	        None => return rbtdre_Verdict::Fail(format!("unknown credential role: {}", role)),
797	    };
798	    let probe_result = match rbtdri_invoke_global(ctx, probe_colophon, &[], &[]) {
799	        Ok(r) => r,
800	        Err(e) => {
801	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
802	        }
803	    };
804	    let _ = std::fs::write(
805	        dir.join(format!("probe-{}-stdout.txt", role)),
806	        &probe_result.stdout,
807	    );
808	    let _ = std::fs::write(
809	        dir.join(format!("probe-{}-stderr.txt", role)),
810	        &probe_result.stderr,
811	    );
812	    if probe_result.exit_code != 0 {
813	        return rbtdre_Verdict::Fail(format!(
814	            "access-probe {} exit {}\n{}",
815	            role, probe_result.exit_code, probe_result.stderr
816	        ));
817	    }
818	
819	    rbtdre_Verdict::Pass
820	}
